#include <bits/stdc++.h>
using namespace std;

const int N=30005;

int n,m,d[N];
vector<int> g[N];
queue<int> q;
bitset<N> f[N];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=0,u,v;i<m;i++){
        scanf("%d%d",&u,&v);
        g[v].push_back(u);
        d[u]++;
    }
    for(int i=1;i<=n;i++){
        f[i].set(i);
        if(!d[i])
            q.push(i);
    }
    while(q.size()){
        int x=q.front();
        q.pop();
        for(int y:g[x]){
            f[y]|=f[x];
            if(!--d[y])
                q.push(y);
        }
    }
    for(int i=1;i<=n;i++)
        printf("%d\n",f[i].count());
    return 0;
}
